CustomField.formula:
(5 * FLOOR( ( DATEVALUE(Stage_End__c  ) - DATE( 1900, 1, 8) ) / 7 ) 
    + MIN( 5, MOD( DATEVALUE(Stage_End__c  ) - DATE( 1900, 1, 8), 7 )  ) 
) - 
(5 * FLOOR( ( DATEVALUE(Stage_Start__c  )- DATE( 1900, 1, 8) ) / 7 ) 
      + MIN( 5, MOD( DATEVALUE(Stage_Start__c  )- DATE( 1900, 1, 8), 7 ) ) 
)
